findings.suggestion:
BEFORE:
const model: LanguageModelV2 = {
  specificationVersion: 'v2',
  provider: 'test-provider',
  modelId: 'test-model',
  supportedUrls: {},
  doGenerate: async (opts) => { /* capture logic */ },
  doStream: async () => ({
    stream: new ReadableStream({
      start(controller) {
        controller.enqueue({ type: 'text-start' as const, ... })
        controller.enqueue({ type: 'text-delta' as const, ... })
        controller.enqueue({ type: 'finish' as const, ... })
        controller.close()
      },
    }),
  }),
}

AFTER:
Extend createTestModel to accept a doGenerate override:

function createTestModel(options: {
  generateResult?: ...,
  doGenerate?: (opts: LanguageModelV2CallOptions) => Promise<...>,
} = {}): LanguageModelV2

Then:
const model = createTestModel({
  doGenerate: async (opts) => {
    receivedPrompt = opts.prompt
    receivedToolDefs = (opts.tools ?? []) as ...
    return { content: [...], finishReason: 'stop', usage: {...}, warnings: [] }
  },
})

WHY: Eliminates ~10 lines of duplicated doStream boilerplate and shortens the test to under 50 lines. The createTestModel helper already exists -- extending it is simpler than maintaining two copies.

